    Program p = new SimpleProgramBuilder().emitNop().emitWrite("x").emitRead("x").emitIfJump(2).buildProgram();
    AnalysisResult<VarSet> result = p.analyze(new InitializedVariablesAnalyzer());
    Assert.assertEquals("0: nop []\n1: write x [x]\n2: read x [x]\n3: ifjump 2 [x]\n4: end [x]\n", result.toString());
